		}
	}
	newMembers := []Member{}
	found := false
	for _, m := range members {
		if m.Address == addr {
			found = true
			continue
		}
		newMembers = append(newMembers, m)
	}
	if !found {
		panic("member not found")
	}
	members = newMembers
}

